    my ($content) = @_;
    my %files;
    my $in_files = 0;
    for my $line (split /\n/, $content) {
        if ($line eq 'files:') {
            $in_files = 1;
            next;
        }
        if ($in_files && $line =~ /^(\S+)\s+(\S+)$/) {
            $files{$1} = $2;
        }
    }
    return %files;
}

